// Field substitution only (A6/B1) -- deterministic, no AI. Fills the
// fixed brand shell for E1-E5 with values read from the Tier Map,
// Project Document, and contact record -- never re-derived here.

const fs = require('fs');
const path = require('path');

const prefix = $json.project_prefix;
const tierMap = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'tier_map.json'), 'utf8'));
const doc = JSON.parse(fs.readFileSync(path.join('Working', prefix, 'project_document.json'), 'utf8'));

const TEMPLATE_DIR = path.join('Originals', 'brand_shell'); // read-only master set
const OUT_DIR = path.join('Working', prefix, 'email_templates');
fs.mkdirSync(OUT_DIR, { recursive: true });

const templates = ['E1_OPEN', 'E2_VALUE', 'E3_CLOSE', 'E4_FULL', 'E5_WHITE_LABEL'];

for (const t of templates) {
  let shell = fs.readFileSync(path.join(TEMPLATE_DIR, t + '.html'), 'utf8');
  shell = shell
    .replace(/{{SOLICITATION_NAME}}/g, doc.decoded_facts ? 'the solicitation' : '')
    .replace(/{{MID_PRICE}}/g, tierMap.mid.price)
    .replace(/{{FULL_PRICE}}/g, tierMap.full.price)
    .replace(/{{UNSUBSCRIBE_LINK}}/g, 'https://circleofcareacademy.org/unsubscribe.php')
    .replace(/{{NDA_LINK}}/g, `https://circleofcareacademy.org/${prefix}-nda.html`);
  fs.writeFileSync(path.join(OUT_DIR, t + '.html'), shell, 'utf8');
}

return [{ json: { project_prefix: prefix, templates_built: templates.length } }];

// Placeholder scan -- no unfilled merge fields survive into a sent
// email (also re-checked independently in Quality Gate, A16).
const fs = require('fs');
const path = require('path');
const dir = path.join('Working', $json.project_prefix, 'email_templates');
const issues = [];
for (const f of fs.readdirSync(dir)) {
  const content = fs.readFileSync(path.join(dir, f), 'utf8');
  if (/{{.*?}}/.test(content)) issues.push({ file: f, reason: 'unfilled_placeholder' });
}
return [{ json: { project_prefix: $json.project_prefix, placeholder_scan_issues: issues } }];
